import scala.util.matching.Regex

def solve(code: Array[String], businessLine: Array[String], isActive: Array[Boolean]): Array[String] = {
    val validBusinessLines = Set("electronics", "grocery", "pharmacy", "restaurant")
    val pattern: Regex = "^[a-zA-Z0-9_]+$".r

    def isValidCode(c: String): Boolean = {
        c.nonEmpty && pattern.matches(c)
    }

    def getBusinessLineOrder(bl: String): Int = bl match {
        case "electronics" => 0
        case "grocery" => 1
        case "pharmacy" => 2
        case "restaurant" => 3
        case _ => 4
    }

    val validCoupons = (code, businessLine, isActive).zipped.toArray
        .filter { case (c, bl, active) =>
            active && isValidCode(c) && validBusinessLines.contains(bl)
        }
        .map { case (c, bl, _) => (bl, c) }

    val sortedCoupons = validCoupons.sortBy { case (bl, c) =>
        (getBusinessLineOrder(bl), c)
    }

    sortedCoupons.map { case (_, c) => c }
}
